const ids = $.steps.extractIds.output.messageIds || [];
let emailSummary = 'Email IDs found: ' + ids.length + '\n\n';
ids.forEach((id, i) => {
  emailSummary += (i + 1) + '. Message ID: ' + id + '\n';
});
return { emailSummary, emailCount: ids.length };

const d = $.steps.compileEmailData.output;
const today = new Date().toISOString().slice(0, 10);

let prompt = 'You are an expert email management assistant. Organize and prioritize the following email inbox data.\n\n';
prompt += 'EMAIL INBOX DATA (' + d.emailCount + ' emails found):\n';
prompt += d.emailSummary + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Categorize emails into: urgent, important, informational, promotional, spam\n';
prompt += '- Suggest priority actions for each category\n';
prompt += '- Create an executive summary of the inbox state\n';
prompt += '- Recommend which emails need immediate attention\n';
prompt += '- Generate a daily email digest\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "reportDate": "' + today + '",\n';
prompt += '  "totalEmails": ' + d.emailCount + ',\n';
prompt += '  "categories": {\n';
prompt += '    "urgent": { "count": 0, "action": "description" },\n';
prompt += '    "important": { "count": 0, "action": "description" },\n';
prompt += '    "informational": { "count": 0, "action": "description" },\n';
prompt += '    "promotional": { "count": 0, "action": "description" },\n';
prompt += '    "spam": { "count": 0, "action": "description" }\n';
prompt += '  },\n';
prompt += '  "executiveSummary": "overview of inbox state",\n';
prompt += '  "topPriorities": ["action item 1", "action item 2"],\n';
prompt += '  "dailyDigest": "formatted daily email digest text",\n';
prompt += '  "recommendations": ["recommendation 1", "recommendation 2"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { totalEmails: 0, executiveSummary: raw, categories: {}, topPriorities: [], dailyDigest: raw, recommendations: [] }; }

const ai = $.steps.parseAI.output;
const today = ai.reportDate || new Date().toISOString().slice(0, 10);

let report = 'EMAIL MANAGEMENT REPORT - ' + today + '\n';
report += '='.repeat(50) + '\n\n';
report += 'EXECUTIVE SUMMARY\n';
report += '-'.repeat(30) + '\n';
report += (ai.executiveSummary || 'No summary available') + '\n\n';
report += 'TOTAL EMAILS: ' + (ai.totalEmails || 0) + '\n\n';
report += 'CATEGORIES\n';
report += '-'.repeat(30) + '\n';
const cats = ai.categories || {};
Object.keys(cats).forEach(cat => {
  const c = cats[cat];
  report += '  ' + cat.toUpperCase() + ': ' + (c.count || 0) + ' emails\n';
  report += '    Action: ' + (c.action || 'N/A') + '\n';
});
report += '\nTOP PRIORITIES\n';
report += '-'.repeat(30) + '\n';
(ai.topPriorities || []).forEach((p, i) => {
  report += '  ' + (i + 1) + '. ' + p + '\n';
});
report += '\nDAILY DIGEST\n';
report += '-'.repeat(30) + '\n';
report += (ai.dailyDigest || 'No digest available') + '\n\n';
report += 'RECOMMENDATIONS\n';
report += '-'.repeat(30) + '\n';
(ai.recommendations || []).forEach((r, i) => {
  report += '  ' + (i + 1) + '. ' + r + '\n';
});
report += '\n---\nGenerated by One CLI | Claude AI\n';

const fileName = 'email-report-' + today + '.txt';
return { report, fileName };
